def solve(nums: list[int], k: int) -> int:
    n = len(nums)
    prefix_xor = [0] * (n + 1)
    for i in range(n):
        prefix_xor[i+1] = prefix_xor[i] ^ nums[i]

    # Compute maximum possible XOR of any subarray
    max_xor = 0
    for i in range(n):
        current = 0
        for j in range(i, n):
            current ^= nums[j]
            max_xor = max(max_xor, current)

    low, high = 0, max_xor
    answer = high

    while low <= high:
        mid = (low + high) // 2
        # Check if it's possible to split into k parts with max XOR <= mid
        dp = [[False] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = True
        for i in range(1, n + 1):
            for j in range(1, k + 1):
                for m in range(i):
                    if dp[m][j-1] and (prefix_xor[i] ^ prefix_xor[m]) <= mid:
                        dp[i][j] = True
                        break
        if dp[n][k]:
            answer = mid
            high = mid - 1
        else:
            low = mid + 1
    return answer
